import { CommonModule } from '@angular/common';
import { Component, OnDestroy, OnInit } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { MatCardModule } from '@angular/material/card';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { Subscription, switchMap, catchError, of } from 'rxjs';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, MatCardModule, MatProgressSpinnerModule],
  template: `
    <mat-card>
      <mat-card-header>
        <mat-card-title>Dashboard</mat-card-title>
        <mat-card-subtitle>Vista general del sistema</mat-card-subtitle>
      </mat-card-header>

      <mat-card-content>
        <div class="dashboard-grid">
          <mat-card class="half-card">
            <mat-card-header>
              <mat-card-title>Hora actual</mat-card-title>
            </mat-card-header>
            <mat-card-content>
              <div class="time-value">{{ formatTime(currentTime) }}</div>
              <div class="time-subtitle">Actualizado en tiempo real</div>
            </mat-card-content>
          </mat-card>

          <mat-card class="half-card">
            <mat-card-header>
              <mat-card-title>Clima</mat-card-title>
              <mat-card-subtitle>{{ locationLabel }}</mat-card-subtitle>
            </mat-card-header>
            <mat-card-content>
              <div class="loading" *ngIf="weatherLoading">
                <mat-progress-spinner diameter="40" mode="indeterminate"></mat-progress-spinner>
              </div>

              <p class="error-msg" *ngIf="!weatherLoading && weatherError">{{ weatherError }}</p>

              <div class="weather" *ngIf="!weatherLoading && !weatherError && weather">
                <div class="weather-temp">{{ weather.temperature }} °C</div>
                <div class="weather-row">
                  <span class="weather-label">Estado:</span>
                  <span class="weather-value">{{ weather.description }}</span>
                </div>
                <div class="weather-row">
                  <span class="weather-label">Viento:</span>
                  <span class="weather-value">{{ weather.windSpeed }} km/h</span>
                </div>
                <div class="weather-updated">
                  Actualizado: {{ weather.updatedAt }}
                </div>
              </div>
            </mat-card-content>
          </mat-card>
        </div>
      </mat-card-content>
    </mat-card>
  `,
  styles: [
    `
      .dashboard-grid {
        display: flex;
        gap: 16px;
        align-items: stretch;
        flex-wrap: wrap;
      }

      .half-card {
        flex: 1 1 50%;
        min-width: 320px;
      }

      .time-value {
        font-size: 34px;
        font-weight: 700;
        letter-spacing: 0.2px;
      }

      .time-subtitle {
        margin-top: 6px;
        opacity: 0.8;
        font-size: 12px;
      }

      .loading {
        display: flex;
        align-items: center;
        justify-content: center;
        padding: 18px 0;
      }

      .error-msg {
        color: #c62828;
        margin: 0;
      }

      .weather-temp {
        font-size: 34px;
        font-weight: 700;
      }

      .weather-row {
        display: flex;
        gap: 8px;
        margin-top: 6px;
      }

      .weather-label {
        opacity: 0.8;
        font-size: 13px;
      }

      .weather-value {
        font-size: 13px;
        font-weight: 500;
      }

      .weather-updated {
        margin-top: 10px;
        opacity: 0.8;
        font-size: 12px;
      }
    `,
  ],
})
export class DashboardComponent implements OnInit, OnDestroy {
  currentTime: Date = new Date();
  private clockTimer: number | null = null;

  locationLabel = 'San Pedro Sula, Cortés, Honduras';
  weatherLoading = false;
  weatherError = '';
  weather:
    | {
        temperature: number;
        description: string;
        windSpeed: number;
        updatedAt: string;
      }
    | null = null;

  private subs = new Subscription();

  constructor(private http: HttpClient) {}

  ngOnInit(): void {
    this.clockTimer = window.setInterval(() => {
      this.currentTime = new Date();
    }, 1000);

    this.loadWeather();
  }

  ngOnDestroy(): void {
    if (this.clockTimer) window.clearInterval(this.clockTimer);
    this.subs.unsubscribe();
  }

  formatTime(d: Date): string {
    try {
      return d.toLocaleTimeString('es-HN', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch {
      return d.toLocaleTimeString();
    }
  }

  private loadWeather(): void {
    this.weatherLoading = true;
    this.weatherError = '';
    this.weather = null;

    // 1) Geocoding (lat/lon) a partir de la dirección.
    const geocodeUrl =
      'https://geocoding-api.open-meteo.com/v1/search?name=' +
      encodeURIComponent(this.locationLabel) +
      '&count=1&language=es&format=json';

    type GeocodeResponse = { results: Array<{ latitude: number; longitude: number }> };
    type ForecastResponse = {
      current: {
        time: string;
        temperature_2m: number;
        weather_code: number;
        wind_speed_10m: number; // m/s
      };
    };

    const obs = this.http.get<GeocodeResponse>(geocodeUrl).pipe(
      switchMap((geo) => {
        const first = geo?.results?.[0];
        if (!first) {
          throw new Error('No se pudo obtener la ubicación para el clima.');
        }

        // 2) Forecast con el clima actual.
        const forecastUrl =
          `https://api.open-meteo.com/v1/forecast?latitude=${first.latitude}` +
          `&longitude=${first.longitude}` +
          `&current=temperature_2m,weather_code,wind_speed_10m` +
          `&timezone=America%2FTegucigalpa` +
          `&wind_speed_unit=kmh`;

        return this.http.get<ForecastResponse>(forecastUrl);
      }),
      catchError((err) => {
        this.weatherLoading = false;
        this.weatherError =
          err?.error?.message ?? err?.message ?? 'No se pudo cargar el clima.';
        return of(null);
      })
    );

    this.subs.add(
      obs.subscribe((res) => {
        this.weatherLoading = false;
        if (!res) return;

        const weatherCode = res.current.weather_code;
        const desc = this.weatherCodeToDescriptionEs(weatherCode);

        this.weather = {
          temperature: Math.round(res.current.temperature_2m),
          description: desc,
          windSpeed: Math.round(res.current.wind_speed_10m),
          updatedAt: this.formatWeatherTime(res.current.time),
        };
      })
    );
  }

  private formatWeatherTime(value: string): string {
    const d = new Date(value);
    if (isNaN(d.getTime())) return value;
    try {
      return d.toLocaleString('es-HN', { dateStyle: 'short', timeStyle: 'short' });
    } catch {
      return d.toLocaleString();
    }
  }

  private weatherCodeToDescriptionEs(code: number): string {
    // Mapeo básico según códigos WMO (Open-Meteo).
    if (code === 0) return 'Cielo despejado';
    if (code === 1 || code === 2) return 'Poco nublado';
    if (code === 3) return 'Nublado';
    if (code === 45 || code === 48) return 'Niebla';
    if (code >= 51 && code <= 57) return 'Llovizna';
    if (code >= 61 && code <= 67) return 'Lluvia';
    if (code >= 71 && code <= 77) return 'Nieve';
    if (code >= 80 && code <= 82) return 'Chubascos';
    if (code >= 95) return 'Tormenta';
    return `Estado ${code}`;
  }
}
